import { createFincode } from "@fincode/node";

const API_KEY = "<Secret API Key>";

(async () => {
    const fincode = createFincode({ apiKey: API_KEY, isLiveMode: false });

    try {
        // リクエストの送信
        const customer = await fincode.customers.create({
            name: "John Doe",
            email: "john@example.com",
        });
    } catch (e) {
        // エラーの処理
    }
})();

package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
)

func main() {

	apiKey := "<Secret API Key>"

	body := CreatingCustomerRequest{
		Email:   stringPointer("john@example.com"),
		Name:    stringPointer("John Doe"),
		PhoneCC: stringPointer("81"),
		PhoneNo: stringPointer("1234567890"),
	}

	marshalledBody, _ := json.Marshal(body)

	// リクエストの作成
	req, _ := http.NewRequest("POST", "https://api.test.fincode.jp/v1/customers", bytes.NewBuffer(marshalledBody))
	req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", apiKey))
	req.Header.Set("Content-Type", "application/json")

	// リクエストの送信
	client := &http.Client{}
	res, err := client.Do(req)
	if err != nil {
		log.Fatal(err)
	}
	defer res.Body.Close()

}

type CreatingCustomerRequest struct {
	ID           *string `json:"id,omitempty"`
	Name         *string `json:"name,omitempty"`
	Email        *string `json:"email,omitempty"`
	PhoneCC      *string `json:"phone_cc,omitempty"`
	PhoneNo      *string `json:"phone_no,omitempty"`
	AddrCity     *string `json:"addr_city,omitempty"`
	AddrCountry  *string `json:"addr_country,omitempty"`
	AddrLine1    *string `json:"addr_line_1,omitempty"`
	AddrLine2    *string `json:"addr_line_2,omitempty"`
	AddrLine3    *string `json:"addr_line_3,omitempty"`
	AddrPostCode *string `json:"addr_post_code,omitempty"`
	AddrState    *string `json:"addr_state,omitempty"`
}

func stringPointer(s string) *string {
	return &s
}

import requests

api_key = '<Secret API Key>'

url = f'https://api.test.fincode.jp/v1/customers'

# ヘッダーを設定
headers = {
    'Authorization': f'Bearer {api_key}',
    'Content-Type': 'application/json'
}

data = {
    "name": "John Doe",
    "email": "john@example.com"
}

# HTTP POSTリクエストの送信
try:
    response = requests.post(url, headers=headers, json=data)

    # レスポンスの処理
    if response.status_code == 200:
        # 成功した場合の処理
        print(f"Success: {response.json()}")
    else:
        # エラーの処理
        print(f"Error: {response.json()}")
except requests.RequestException as e:
    # 通信エラーの処理
    print(f"Request error: {e}")

