func main() {
	apiKey := "<Secret API Key>"

	body := &bytes.Buffer{}
	writer := multipart.NewWriter(body)

	file, err := os.Open("/path/to/your/company_stamp.png")
	if err != nil {
		log.Fatalf("ファイルオープンエラー: %v", err)
	}
	defer file.Close()

	part, err := writer.CreateFormFile("data", "company_stamp.png")
	if err != nil {
		log.Fatalf("マルチパート作成エラー: %v", err)
	}
	io.Copy(part, file)
	writer.Close()

	url := "https://api.test.fincode.jp/v1/company_stamps"
	req, err := http.NewRequest("POST", url, body)
	if err != nil {
		log.Fatalf("リクエスト作成エラー: %v", err)
	}
	req.Header.Set("Authorization", "Bearer "+apiKey)
	req.Header.Set("Content-Type", writer.FormDataContentType())

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		log.Fatalf("リクエスト送信エラー: %v", err)
	}
	defer resp.Body.Close()

	respBody, _ := io.ReadAll(resp.Body)
	fmt.Println(string(respBody))
}

